class Cache:
    def __init__(self):
        self._data = {}
    def get(self, url):
        if url in self._data:
            return self._data[url], True
        return None, False
    def set(self, url, body):
        self._data[url] = body
c = Cache()
c.set("u1", {"ok": True})
print(c.get("u1"))
print(c.get("missing"))

